<?php
namespace App\Services\Security;use App\Models\{User,WorkerPayoutReviewEvidence};use Carbon\Carbon;
class EvidenceRetentionService{public function calculateRetentionUntil(WorkerPayoutReviewEvidence $e):?Carbon{return $e->review?->status==='cancelled'?now()->addYear():null;}public function scheduleDeletion(WorkerPayoutReviewEvidence $e,User $a,string $reason):WorkerPayoutReviewEvidence{$e->update(['retention_until'=>$this->calculateRetentionUntil($e),'scheduled_deletion_at'=>null]);$e->events()->create(['worker_payout_review_id'=>$e->worker_payout_review_id,'actor_id'=>$a->id,'event_type'=>'retention_scheduled','description'=>$reason,'created_at'=>now()]);return $e->refresh();}public function canDeleteByRetention(WorkerPayoutReviewEvidence $e):bool{return $e->scheduled_deletion_at?->isPast()??false;}}
